#!/bin/bash
#
# Cross-compiles Ian Lance Taylor's libbacktrace (https://github.com/ianlancetaylor/libbacktrace)
# for all Android ABIs using the NDK clang toolchain.
#
# Boost.Stacktrace's "backtrace" backend (BOOST_STACKTRACE_USE_BACKTRACE) needs <backtrace.h> +
# libbacktrace, which the Android NDK does NOT ship. This produces them so the Zano Android build
# can use the full stacktrace backend (function names + file:line) instead of the basic dladdr one.
#
# Output layout (mirrors _libs_android/boost):
#   _libs_android/libbacktrace/include/{backtrace.h,backtrace-supported.h}
#   _libs_android/libbacktrace/<ABI>/lib/libbacktrace.a
#   _libs_android/libbacktrace/<ABI>/VERSION
#
# Env:
#   ANDROID_NDK_ROOT   (required) path to the NDK (provided by .github/actions/android)
#   ANDROID_TARGET     (default 26) min API level — must match the Boost/Zano android builds
#   NDK_HOST_TAG       (default linux-x86_64) prebuilt toolchain host tag
#   LIBBACKTRACE_URL   (default upstream) git URL
#   LIBBACKTRACE_REF   (default master) git ref/commit to build — pin this for reproducibility

set -e

PROJECT_ROOT="$(realpath "$(dirname "$0")/../../..")"
PLATFORM_ROOT="$(realpath "${PROJECT_ROOT}/thirdparty/libbacktrace/android")"
TARGET_ROOT="${PROJECT_ROOT}/_libs_android/libbacktrace"
ANDROID_TARGET=${ANDROID_TARGET:-26}
NDK_HOST_TAG=${NDK_HOST_TAG:-linux-x86_64}
LIBBACKTRACE_URL=${LIBBACKTRACE_URL:-https://github.com/ianlancetaylor/libbacktrace.git}
LIBBACKTRACE_REF=${LIBBACKTRACE_REF:-master}

if [ -z "${ANDROID_NDK_ROOT:-}" ]; then
  echo "ANDROID_NDK_ROOT is not set" >&2
  exit 1
fi

TOOLBIN="${ANDROID_NDK_ROOT}/toolchains/llvm/prebuilt/${NDK_HOST_TAG}/bin"
if [ ! -d "${TOOLBIN}" ]; then
  echo "NDK toolchain not found at ${TOOLBIN}" >&2
  exit 1
fi

echo "libbacktrace ref: $LIBBACKTRACE_REF"
echo "Android NDK:      $ANDROID_NDK_ROOT"
echo "Android Target:   $ANDROID_TARGET"
echo "==============================================================================="

# --- fetch sources -----------------------------------------------------------
SRC_DIR="${PLATFORM_ROOT}/libbacktrace"
if [ ! -d "${SRC_DIR}/.git" ]; then
  rm -rf "${SRC_DIR}"
  git clone "${LIBBACKTRACE_URL}" "${SRC_DIR}"
fi
git -C "${SRC_DIR}" fetch --all --tags || true
git -C "${SRC_DIR}" checkout "${LIBBACKTRACE_REF}"

# --- build one ABI -----------------------------------------------------------
# args: <abi> <configure-host-triple> <ndk-clang-wrapper>
build_arch() {
  local ARCH="$1" HOST="$2" CLANG="$3"
  local BUILD_DIR="${PLATFORM_ROOT}/build-${ARCH}"
  echo "=== libbacktrace ${ARCH} (host=${HOST}, cc=${CLANG}) ==="

  rm -rf "${BUILD_DIR}"
  mkdir -p "${BUILD_DIR}"
  (
    cd "${BUILD_DIR}"
    CC="${TOOLBIN}/${CLANG}" \
    AR="${TOOLBIN}/llvm-ar" \
    RANLIB="${TOOLBIN}/llvm-ranlib" \
    NM="${TOOLBIN}/llvm-nm" \
    STRIP="${TOOLBIN}/llvm-strip" \
    CFLAGS="-O2 -fPIC -funwind-tables" \
      "${SRC_DIR}/configure" --host="${HOST}" --enable-static --disable-shared
    make -j"$(nproc)" libbacktrace.la
  )

  if [ ! -f "${BUILD_DIR}/.libs/libbacktrace.a" ]; then
    echo "libbacktrace failed to build for ${ARCH}" >&2
    exit 1
  fi

  mkdir -p "${TARGET_ROOT}/${ARCH}/lib"
  cp "${BUILD_DIR}/.libs/libbacktrace.a" "${TARGET_ROOT}/${ARCH}/lib/"
  echo "${LIBBACKTRACE_REF}" > "${TARGET_ROOT}/${ARCH}/VERSION"
}

rm -rf "${TARGET_ROOT}"
build_arch arm64-v8a   aarch64-linux-android "aarch64-linux-android${ANDROID_TARGET}-clang"
build_arch armeabi-v7a arm-linux-androideabi "armv7a-linux-androideabi${ANDROID_TARGET}-clang"
build_arch x86         i686-linux-android    "i686-linux-android${ANDROID_TARGET}-clang"
build_arch x86_64      x86_64-linux-android  "x86_64-linux-android${ANDROID_TARGET}-clang"

# --- shared headers ----------------------------------------------------------
# backtrace.h is a committed source header; backtrace-supported.h is generated by configure.
# They are effectively identical across Android ABIs, so a single copy (from arm64-v8a) is used,
# mirroring how _libs_android/boost/include is shared across ABIs.
mkdir -p "${TARGET_ROOT}/include"
cp "${SRC_DIR}/backtrace.h" "${TARGET_ROOT}/include/"
cp "${PLATFORM_ROOT}/build-arm64-v8a/backtrace-supported.h" "${TARGET_ROOT}/include/"

echo "==============================================================================="
echo "libbacktrace android build done -> ${TARGET_ROOT}"
